package com.example.sharehandler

import android.content.Intent
import android.graphics.Bitmap
import android.net.Uri
import android.os.Bundle
import android.provider.MediaStore
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import java.io.ByteArrayOutputStream
import java.io.IOException

class ShareActivity : AppCompatActivity() {
    
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share)
        
        handleIncomingShare()
    }
    
    private fun handleIncomingShare() {
        val intent = intent
        val action = intent.action
        val type = intent.type
        
        if (Intent.ACTION_SEND == action && type != null) {
            if (type.startsWith("text/")) {
                handleTextShare()
            } else if (type.startsWith("image/")) {
                handleImageShare()
            }
        }
    }
    
    private fun handleTextShare() {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        if (sharedText != null) {
            processSharedText(sharedText)
        }
    }
    
    private fun handleImageShare() {
        val imageUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
        if (imageUri != null) {
            processSharedImage(imageUri)
        }
    }
    
    private fun processSharedText(text: String) {
        // Process the shared text (URL or plain text)
        if (text.startsWith("http://") || text.startsWith("https://")) {
            // Handle URL
            Toast.makeText(this, "Shared URL: $text", Toast.LENGTH_LONG).show()
        } else {
            // Handle plain text
            Toast.makeText(this, "Shared text: $text", Toast.LENGTH_LONG).show()
        }
    }
    
    private fun processSharedImage(uri: Uri) {
        try {
            val bitmap = MediaStore.Images.Media.getBitmap(contentResolver, uri)
            // Process the shared image
            Toast.makeText(this, "Shared image received", Toast.LENGTH_LONG).show()
            // You can save the bitmap or process it further here
        } catch (e: IOException) {
            e.printStackTrace()
            Toast.makeText(this, "Error processing image", Toast.LENGTH_LONG).show()
        }
    }
}